import{c as e,Q as r,j as a,m as p}from"./chunks/framework.mmTo2oFH.js";const _=JSON.parse('{"title":"关于","description":"","frontmatter":{"title":"关于"},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1780245087000}'),i={name:"about.md"};function o(s,t,l,n,b,d){return r(),a("div",null,[...t[0]||(t[0]=[p('<h1 id="关于-jinsystem" tabindex="-1">关于 JinSystem <a class="header-anchor" href="#关于-jinsystem" aria-label="Permalink to &quot;关于 JinSystem&quot;">​</a></h1><p><strong>JinSystem</strong> 是基于 Excel 知识库自动生成的个人认知站点，遵循一个简单原则：</p><blockquote><p><strong>物质低配 · 认知高配 · 心态顶配</strong></p></blockquote><h2 id="元认知-在正确的道路上长期主义" tabindex="-1">元认知：在正确的道路上长期主义 <a class="header-anchor" href="#元认知-在正确的道路上长期主义" aria-label="Permalink to &quot;元认知：在正确的道路上长期主义&quot;">​</a></h2><div class="reading-prose"><p>真正的成长，<br> 从来不是一时的激情与爆发…<br> 而是：<br> 能够不断审视自己、修正自己，并始终走在正确的方向上。</p><p>清晰的目标指引方向，<br> 匹配的难度带来突破，<br> 极度的专注沉淀势能，<br> 即时的反馈强化坚持。</p><p>而这一切的核心，都源于「元认知」。</p><p>所谓元认知，就是：<br> 能跳出当下情绪与环境，更高维度地观察自己。</p><p>知道自己为什么焦虑；<br> 知道自己为什么懒散；<br> 知道什么值得长期坚持；<br> 也知道什么只是短期诱惑。</p><p>不被情绪牵引，<br> 不被外界裹挟，<br> 不因暂时没有结果而轻易否定自己。</p><p>因为真正有价值的东西，往往都需要长期积累：</p><ul><li>认知如此；</li><li>财富如此；</li><li>能力如此；</li><li>身体如此；</li><li>人生亦如此。</li></ul><p>真正厉害的人，未必是最快成功的人，而是：<br> 在正确道路上，依然能够长期保持清醒、专注与迭代的人。</p><p>允许缓慢，但绝不停止；<br> 允许孤独，但绝不迷失。</p><p>专注自身，持续精进。<br> 在无人喝彩的日子里，默默完成认知与生命层级的跃迁。</p><p>终有一天，时间会奖励那个：始终清醒前行的人。</p></div>',5)])])}const m=e(i,[["render",o]]);export{_ as __pageData,m as default};
